## Line Diff Engine
```python
def diff_lines(old: list[str], new: list[str]) -> list[tuple[str, str]]:
    m, n = len(old), len(new)
    dp = [[0] * (n + 1) for _ in range(m + 1)]
    for i in range(m - 1, -1, -1):
        for j in range(n - 1, -1, -1):
            if old[i] == new[j]:
                dp[i][j] = dp[i + 1][j + 1] + 1
            else:
                dp[i][j] = max(dp[i + 1][j], dp[i][j + 1])
    i = j = 0
    out: list[tuple[str, str]] = []
    while i < m and j < n:
        if old[i] == new[j]:
            out.append(("=", old[i]))
            i += 1
            j += 1
        elif dp[i + 1][j] >= dp[i][j + 1]:
            out.append(("-", old[i]))
            i += 1
        else:
            out.append(("+", new[j]))
            j += 1
    while i < m:
        out.append(("-", old[i]))
        i += 1
    while j < n:
        out.append(("+", new[j]))
        j += 1
    return out
```

